import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Nav from './Nev';

const Cart = () => {
  const navigate = useNavigate();
  const [cartItems, setCartItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const uid = localStorage.getItem("id", 0);

  useEffect(() => {
    if (!localStorage.getItem("islogin")) {
      navigate('/login');
      return;
    }
    getProducts();
  }, []);

  function getProducts() {
    fetch('http://localhost/Petshop/showcart.php?uid=' + uid)
      .then((res) => res.json())
      .then((data) => {
        const itemsWithId = data.map((item, index) => ({
          ...item,
          id: index + 1,
          quantity: parseInt(item.quantity)
        }));
        setCartItems(itemsWithId);
        setLoading(false);
      })
      .catch((error) => {
        console.error('Error:', error);
        setLoading(false);
      });
  }

  const increaseQuantity = (id) => {
    setCartItems(prev => prev.map(item =>
      item.id === id ? { ...item, quantity: item.quantity + 1 } : item
    ));
  };

  const decreaseQuantity = (id) => {
    setCartItems(prev => prev.map(item =>
      item.id === id && item.quantity > 1 ? { ...item, quantity: item.quantity - 1 } : item
    ));
  };

  const deleteItem = (id) => {
    setCartItems(prev => prev.filter(item => item.id !== id));
  };

  const calculateTotal = () =>
    cartItems.reduce((total, item) => total + (item.price * item.quantity), 0);

  const calculateTotalItems = () =>
    cartItems.reduce((total, item) => total + item.quantity, 0);

  function nextpage() {
    localStorage.setItem("totalitem", calculateTotalItems());
    localStorage.setItem("item", calculateTotal());
    navigate('/checkout');
  }

  const styles = {
    page: {
      minHeight: '100vh',
      backgroundColor: '#f0f4f8',
      fontFamily: "'Segoe UI', sans-serif",
    },
    container: {
      maxWidth: '900px',
      margin: '30px auto',
      padding: '0 16px 40px',
    },
    header: {
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      marginBottom: '24px',
    },
    title: {
      fontSize: '28px',
      fontWeight: '700',
      color: '#1a202c',
      margin: 0,
    },
    badge: {
      backgroundColor: '#48bb78',
      color: 'white',
      padding: '4px 12px',
      borderRadius: '20px',
      fontSize: '14px',
      fontWeight: '600',
    },
    card: {
      backgroundColor: 'white',
      borderRadius: '16px',
      boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
      overflow: 'hidden',
    },
    emptyCart: {
      textAlign: 'center',
      padding: '60px 20px',
      color: '#718096',
    },
    emptyIcon: {
      fontSize: '64px',
      marginBottom: '16px',
    },
    tableHeader: {
      display: 'grid',
      gridTemplateColumns: '2fr 1fr 1.5fr 1fr 0.8fr',
      padding: '14px 24px',
      backgroundColor: '#f7fafc',
      borderBottom: '2px solid #e2e8f0',
      fontWeight: '600',
      color: '#4a5568',
      fontSize: '13px',
      textTransform: 'uppercase',
      letterSpacing: '0.05em',
    },
    tableRow: {
      display: 'grid',
      gridTemplateColumns: '2fr 1fr 1.5fr 1fr 0.8fr',
      padding: '16px 24px',
      borderBottom: '1px solid #edf2f7',
      alignItems: 'center',
      transition: 'background 0.2s',
    },
    productName: {
      fontWeight: '600',
      color: '#2d3748',
      fontSize: '15px',
    },
    price: {
      color: '#4a5568',
      fontWeight: '500',
    },
    qtyBox: {
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
    },
    qtyBtn: {
      width: '30px',
      height: '30px',
      borderRadius: '8px',
      border: 'none',
      backgroundColor: '#ebf8ff',
      color: '#2b6cb0',
      fontWeight: '700',
      fontSize: '16px',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
    },
    qtyNum: {
      fontWeight: '700',
      fontSize: '16px',
      minWidth: '20px',
      textAlign: 'center',
      color: '#2d3748',
    },
    total: {
      fontWeight: '700',
      color: '#2d3748',
    },
    deleteBtn: {
      backgroundColor: '#fff5f5',
      color: '#e53e3e',
      border: '1px solid #fed7d7',
      borderRadius: '8px',
      padding: '6px 12px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '13px',
    },
    summary: {
      padding: '20px 24px',
      backgroundColor: '#f7fafc',
    },
    summaryRow: {
      display: 'flex',
      justifyContent: 'space-between',
      padding: '8px 0',
      color: '#4a5568',
      fontSize: '15px',
    },
    summaryTotal: {
      display: 'flex',
      justifyContent: 'space-between',
      padding: '12px 0 4px',
      borderTop: '2px solid #e2e8f0',
      marginTop: '8px',
      fontWeight: '700',
      fontSize: '20px',
      color: '#1a202c',
    },
    btnRow: {
      display: 'flex',
      gap: '12px',
      padding: '20px 24px',
      borderTop: '1px solid #edf2f7',
    },
    homeBtn: {
      padding: '12px 24px',
      backgroundColor: '#edf2f7',
      color: '#4a5568',
      border: 'none',
      borderRadius: '10px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '15px',
      flex: '1',
    },
    checkoutBtn: {
      padding: '12px 24px',
      backgroundColor: '#38a169',
      color: 'white',
      border: 'none',
      borderRadius: '10px',
      cursor: 'pointer',
      fontWeight: '700',
      fontSize: '15px',
      flex: '2',
    },
    loadingBox: {
      textAlign: 'center',
      padding: '60px',
      color: '#718096',
      fontSize: '18px',
    }
  };

  return (
    <div style={styles.page}>
      <Nav />
      <div style={styles.container}>
        <div style={styles.header}>
          <h1 style={styles.title}>🛒 Shopping Cart</h1>
          <span style={styles.badge}>{calculateTotalItems()} items</span>
        </div>

        <div style={styles.card}>
          {loading ? (
            <div style={styles.loadingBox}>Loading cart...</div>
          ) : cartItems.length === 0 ? (
            <div style={styles.emptyCart}>
              <div style={styles.emptyIcon}>🛒</div>
              <h3 style={{ color: '#2d3748', marginBottom: '8px' }}>Cart khali hai!</h3>
              <p>Koi product add nahi kiya abhi tak.</p>
              <button
                onClick={() => navigate('/product')}
                style={{ ...styles.checkoutBtn, marginTop: '16px', flex: 'none', padding: '12px 32px' }}
              >
                Products Dekhein
              </button>
            </div>
          ) : (
            <>
              {/* Table Header */}
              <div style={styles.tableHeader}>
                <span>Product</span>
                <span>Price</span>
                <span>Quantity</span>
                <span>Total</span>
                <span>Action</span>
              </div>

              {/* Table Rows */}
              {cartItems.map(item => (
                <div key={item.id} style={styles.tableRow}>
                  <div style={styles.productName}>🐾 {item.pname}</div>
                  <div style={styles.price}>₹{parseInt(item.price).toLocaleString()}</div>
                  <div style={styles.qtyBox}>
                    <button style={styles.qtyBtn} onClick={() => decreaseQuantity(item.id)}>−</button>
                    <span style={styles.qtyNum}>{item.quantity}</span>
                    <button style={styles.qtyBtn} onClick={() => increaseQuantity(item.id)}>+</button>
                  </div>
                  <div style={styles.total}>₹{(item.price * item.quantity).toLocaleString()}</div>
                  <button style={styles.deleteBtn} onClick={() => deleteItem(item.id)}>🗑 Delete</button>
                </div>
              ))}

              {/* Summary */}
              <div style={styles.summary}>
                <div style={styles.summaryRow}>
                  <span>Subtotal ({calculateTotalItems()} items)</span>
                  <span>₹{calculateTotal().toLocaleString()}</span>
                </div>
                <div style={styles.summaryRow}>
                  <span>Delivery</span>
                  <span style={{ color: '#38a169', fontWeight: '600' }}>FREE</span>
                </div>
                <div style={styles.summaryTotal}>
                  <span>Total Amount</span>
                  <span style={{ color: '#38a169' }}>₹{calculateTotal().toLocaleString()}</span>
                </div>
              </div>

              {/* Buttons */}
              <div style={styles.btnRow}>
                <button style={styles.homeBtn} onClick={() => navigate('/')}>
                  ← Continue Shopping
                </button>
                <button style={styles.checkoutBtn} onClick={nextpage}>
                  Proceed to Checkout →
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default Cart;
